<script setup lang="ts">
import { onBeforeUnmount, onMounted, ref } from 'vue'
import type { SampleCorpusStatus } from '../../shared/contracts'
import PageHeader from '../components/PageHeader.vue'
const corpora=ref<SampleCorpusStatus[]>([]);const busy=ref('');const message=ref('');const snackbar=ref(false);let timer:number|undefined
function notify(text:string){message.value=text;snackbar.value=true}
function formatBytes(value:number){if(value<1024)return`${value} B`;const units=['KiB','MiB','GiB','TiB'];let amount=value;let unit=-1;do{amount/=1024;unit+=1}while(amount>=1024&&unit<units.length-1);return`${amount.toFixed(amount>=10?1:2)} ${units[unit]}`}
async function refreshLocal(){corpora.value=await window.mel.corpora.list()}
async function discover(){busy.value='refresh';try{corpora.value=await window.mel.corpora.refresh();notify(`Discovered ${corpora.value.length} approved or reviewable manifests.`)}catch(error){notify(error instanceof Error?error.message:String(error))}finally{busy.value=''}}
async function importManifest(){const path=await window.mel.chooseFile({title:'Import corpus-manifest.json',extensions:['json']});if(!path)return;try{await window.mel.corpora.import(path);await refreshLocal()}catch(error){notify(error instanceof Error?error.message:String(error))}}
async function install(corpus:SampleCorpusStatus){busy.value=corpus.manifest.id;try{const jobs=await window.mel.corpora.install(corpus.manifest.id);notify(jobs.length?`Queued ${jobs.length} verified part downloads.`:'All required parts are already installed.');await refreshLocal()}catch(error){notify(error instanceof Error?error.message:String(error))}finally{busy.value=''}}
async function remove(corpus:SampleCorpusStatus){await window.mel.corpora.remove(corpus.manifest.id);await refreshLocal()}
async function reveal(corpus:SampleCorpusStatus){await window.mel.revealPath(corpus.installRoot)}
onMounted(()=>{void refreshLocal();timer=window.setInterval(refreshLocal,2500)});onBeforeUnmount(()=>timer&&clearInterval(timer))
</script>
<template><div class="page-wrap"><PageHeader eyebrow="Sample Corpus Manager" title="Run the product before supplying your own data" subtitle="Quick Start demonstrates the complete workflow; Full Research preserves the sanitized canonical corpus for scale and repeatability evaluation. Each part is immutable and SHA-256 verified." icon="mdi-archive-eye-outline" color="secondary"><div class="d-flex flex-wrap ga-2 mt-5"><v-btn color="primary" prepend-icon="mdi-cloud-sync-outline" :loading="busy==='refresh'" @click="discover">Discover Releases</v-btn><v-btn variant="tonal" color="secondary" prepend-icon="mdi-file-import-outline" @click="importManifest">Import manifest</v-btn></div></PageHeader><v-row v-if="corpora.length"><v-col v-for="corpus in corpora" :key="`${corpus.manifest.id}-${corpus.manifest.version}`" cols="12" lg="6"><v-hover v-slot="{isHovering,props}"><v-card v-bind="props" class="glass module-card pa-6 h-100" :class="{'is-hovered':isHovering}"><div class="d-flex justify-space-between align-start"><v-avatar :color="corpus.manifest.tier==='quick-start'?'secondary':'primary'" variant="tonal" rounded="lg"><v-icon :icon="corpus.manifest.tier==='quick-start'?'mdi-rocket-launch-outline':'mdi-flask-round-bottom-outline'"/></v-avatar><v-chip :color="corpus.state==='installed'?'success':corpus.state==='blocked'?'error':corpus.state==='partial'?'warning':'primary'" variant="tonal">{{ corpus.state }}</v-chip></div><div class="text-overline mt-5">{{ corpus.manifest.tier }} · v{{ corpus.manifest.version }}</div><div class="text-h5 font-weight-bold">{{ corpus.manifest.title }}</div><p class="text-body-2 text-medium-emphasis mt-3">{{ corpus.manifest.description }}</p><div class="d-flex flex-wrap ga-2"><v-chip size="small" variant="outlined">{{ corpus.manifest.license }}</v-chip><v-chip size="small" :color="corpus.manifest.rightsStatus==='approved'?'success':'warning'" variant="tonal">rights {{ corpus.manifest.rightsStatus }}</v-chip><v-chip size="small" variant="outlined">{{ corpus.manifest.sanitization.prompts }}</v-chip></div><div class="d-flex justify-space-between text-caption text-medium-emphasis mt-5"><span>{{ corpus.installedAssets }} / {{ corpus.totalAssets }} parts</span><span>{{ formatBytes(corpus.installedBytes) }} / {{ formatBytes(corpus.totalBytes) }}</span></div><v-progress-linear :model-value="corpus.totalBytes?corpus.installedBytes/corpus.totalBytes*100:0" color="secondary" rounded height="8" class="mt-2"/><v-alert v-if="corpus.activeJobIds.length" color="info" variant="tonal" density="compact" class="mt-4">{{ corpus.activeJobIds.length }} download job(s) active or recoverable.</v-alert><div class="d-flex flex-wrap ga-2 mt-5"><v-btn color="primary" prepend-icon="mdi-download-multiple" :loading="busy===corpus.manifest.id" :disabled="corpus.state==='blocked'||corpus.state==='installed'" @click="install(corpus)">Install / Resume</v-btn><v-btn v-if="corpus.state==='installed'||corpus.state==='partial'" color="secondary" variant="tonal" prepend-icon="mdi-folder-open-outline" @click="reveal(corpus)">Reveal</v-btn><v-btn v-if="corpus.state==='installed'||corpus.state==='partial'" color="error" variant="text" prepend-icon="mdi-delete-outline" @click="remove(corpus)">Remove files</v-btn></div></v-card></v-hover></v-col></v-row><v-card v-else class="glass pa-10 text-center"><v-icon icon="mdi-archive-search-outline" color="secondary" size="72"/><div class="text-h5 font-weight-bold mt-4">No corpus manifests installed</div><p class="text-medium-emphasis">Discover approved GitHub Releases or import a locally reviewed manifest.</p></v-card><v-snackbar v-model="snackbar" :timeout="5000">{{ message }}</v-snackbar></div></template>
